import java.util.*;
import java.util.stream.*;

public class Main {

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        String left = input.hasNextLine() ? input.nextLine() : "";
        String right = input.hasNextLine() ? input.nextLine() : "";
        System.out.println(left.equals(right) ? "equal" : "different");
        System.out.println(left.codePointCount(0, left.length()) + right.codePointCount(0, right.length()));
    }
}
